export function Suche({ placeholder = "Suchen…" }) {
  return (
    <form role="search" className="flex items-center gap-2 rounded-lg border border-[#e5e7eb] bg-white px-3 py-1.5 w-64">
      <svg className="h-4 w-4 text-[#9ca3af]" viewBox="0 0 20 20" fill="none" stroke="currentColor">
        <circle cx="9" cy="9" r="6" strokeWidth="2" />
        <path d="M14 14l4 4" strokeWidth="2" strokeLinecap="round" />
      </svg>
      <input type="search" placeholder={placeholder} className="flex-1 text-sm text-[#111827] placeholder-[#9ca3af] outline-none" />
    </form>
  );
}

export function Formular({ placeholder = "E-Mail", buttonLabel = "Abonnieren" }) {
  return (
    <form className="flex items-center gap-2">
      <input type="email" placeholder={placeholder} className="rounded-lg border border-[#e5e7eb] bg-white px-3 py-2 text-sm text-[#111827] placeholder-[#9ca3af]" />
      <button className="rounded-lg bg-[#4263EB] px-4 py-2 text-sm font-medium text-white hover:opacity-90">{buttonLabel}</button>
    </form>
  );
}

export function Liste({ items = ["Punkt 1", "Punkt 2", "Punkt 3"] }) {
  return (
    <ul className="space-y-1.5 text-sm text-[#374151]">
      {items.map((label) => (
        <li key={label} className="flex items-center gap-2">
          <span className="h-1.5 w-1.5 rounded-full bg-[#4263EB]" />
          {label}
        </li>
      ))}
    </ul>
  );
}

export function Navbar({ homeLabel = "Home", placeholder = "Suchen…" }) {
  return (
    <nav className="flex items-center justify-between gap-4 px-4 py-2 border-b border-[#e5e7eb] bg-white">
      <a href="#" className="text-sm font-medium text-[#111827]">{homeLabel}</a>
      <form role="search" className="flex items-center gap-2 rounded-lg border border-[#e5e7eb] bg-[#f9fafb] px-3 py-1.5">
        <input type="search" placeholder={placeholder} className="text-sm text-[#111827] placeholder-[#9ca3af] outline-none bg-transparent" />
      </form>
    </nav>
  );
}

export function Hero({ title = "ACME Analytics", subtitle = "Eine kleine Demo-Seite mit echten CSS-Variablen." }) {
  return (
    <header className="px-6 py-10 text-center">
      <h1 className="text-2xl font-semibold text-[#111827]">{title}</h1>
      <p className="mt-2 text-sm text-[#6b7280]">{subtitle}</p>
      <div className="mt-4 flex justify-center gap-2">
        <button className="rounded-lg bg-[#4263EB] px-4 py-2 text-sm font-medium text-white hover:opacity-90">Jetzt starten</button>
        <button className="rounded-lg border border-[#e5e7eb] px-4 py-2 text-sm font-medium text-[#111827] hover:bg-[#f9fafb]">Mehr</button>
      </div>
    </header>
  );
}

export function Footer({ text = "© ACME" }) {
  return (
    <footer className="px-4 py-4 text-center text-xs text-[#9ca3af] border-t border-[#e5e7eb]">
      <p>{text}</p>
    </footer>
  );
}
